const config = $('⚙️ Load Config').item.json;
const tz = config.CONTENT_DAY_TIMEZONE || config.TIMEZONE || 'UTC';
const today = new Date().toLocaleDateString('en-CA', { timeZone: tz });
const rows = $input.all().map(i => i.json);
const dateKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase() === 'date') || 'date';
const valid = rows.filter(r => (r[dateKey] || r.date || '').toString().slice(0, 10) === today);
if (valid.length === 0) return [{ json: { noPostToday: true } }];
const row = valid[valid.length - 1];
return [{ json: { ...row, noPostToday: false } }];

const config = $('⚙️ Load Config').item.json;
const tz = config.CONTENT_DAY_TIMEZONE || config.TIMEZONE || 'UTC';
const today = new Date().toLocaleDateString('en-CA', { timeZone: tz });
const rows = $input.all().map(i => i.json);
const dateKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase() === 'date') || 'Date';
const filtered = rows.filter(r => (r[dateKey] || r.Date || '').toString().slice(0, 10) === today);
if (filtered.length === 0) return [{ json: { noMultilingualToday: true } }];
return filtered.map(r => ({ json: r }));

const config = $('⚙️ Load Config').item.json;
const provider = (config.VOICE_PROVIDER || 'elevenlabs').toLowerCase();
const allPosts = $input.all();

const elevenlabsMap = { 'en': { voice_id: 'EXAVITQu4vr4xnSDxMaL', name: 'Sarah' }, 'es': { voice_id: 'XrExE9yKIg1WjnnlVkGX', name: 'Matilda' }, 'pt-BR': { voice_id: 'GBv7mTt0atIp3Br8iCZE', name: 'Ricardo' }, 'de': { voice_id: 'iP95p4xoKVk53GoZ742B', name: 'Klaus' }, 'fr': { voice_id: 'zrHiDhphv9ZnVXBqCLjz', name: 'Charlotte' }, 'hi': { voice_id: 'hi-IN-Neural2-A', name: 'Aditi' }, 'id': { voice_id: 'id-ID-Standard-B', name: 'Siti' }, 'ar': { voice_id: 'ar-XA-Standard-A', name: 'Layla' }, 'ja': { voice_id: 'ja-JP-Neural2-B', name: 'Yuki' } };
const googleMap = { 'en': { voice_id: 'en-US-Neural2-D', name: 'en-US' }, 'es': { voice_id: 'es-ES-Neural2-B', name: 'es-ES' }, 'pt-BR': { voice_id: 'pt-BR-Neural2-B', name: 'pt-BR' }, 'de': { voice_id: 'de-DE-Neural2-B', name: 'de-DE' }, 'fr': { voice_id: 'fr-FR-Neural2-A', name: 'fr-FR' }, 'hi': { voice_id: 'hi-IN-Neural2-A', name: 'Aditi' }, 'id': { voice_id: 'id-ID-Standard-B', name: 'Siti' }, 'ar': { voice_id: 'ar-XA-Standard-A', name: 'Layla' }, 'ja': { voice_id: 'ja-JP-Neural2-B', name: 'Yuki' } };

function langCode(post) {
  const lang = post.json['Language']?.toLowerCase() || 'en';
  if (lang.includes('spanish')) return 'es';
  if (lang.includes('portuguese')) return 'pt-BR';
  if (lang.includes('german')) return 'de';
  if (lang.includes('french')) return 'fr';
  if (lang.includes('hindi')) return 'hi';
  if (lang.includes('indonesian')) return 'id';
  if (lang.includes('arabic')) return 'ar';
  if (lang.includes('japanese')) return 'ja';
  return 'en';
}

return allPosts.map(post => {
  const lc = langCode(post);
  let voice_config;
  if (provider === 'local') {
    voice_config = { provider: 'local', voice_id: lc, name: 'local', endpoint: (config.TTS_SERVER_URL || 'http://localhost:5000').replace(/\/$/, '') };
  } else if (provider === 'google') {
    const v = googleMap[lc] || googleMap['en'];
    voice_config = { provider: 'google', voice_id: v.voice_id, name: v.name };
  } else {
    const v = elevenlabsMap[lc] || elevenlabsMap['en'];
    voice_config = { provider: 'elevenlabs', voice_id: v.voice_id, name: v.name };
  }
  return {
    json: {
      title: post.json['Translated Title'] || post.json['Title'],
      url: post.json['URL'],
      language: lc,
      language_name: post.json['Language'] || 'English',
      voice_config,
      content_preview: (post.json['Translated Title'] || '').substring(0, 200)
    }
  };
});

const raw = $input.first().json.response || '';
const voiceConfig = $('🎛️ Configure Voice Settings').item.json.voice_config;
const langData = $('🎛️ Configure Voice Settings').item.json;

let audioScript;
try {
  const match = raw.match(/```json\n([\s\S]*?)\n```/) || raw.match(/(\{[\s\S]*\})/);
  audioScript = JSON.parse(match ? (match[1] || match[0]) : raw);
} catch(e) {
  audioScript = {
    podcast_title: langData.title,
    podcast_script: 'Welcome to HowTo-Genie Podcast. ' + langData.content_preview,
    estimated_duration: '10 minutes',
    word_count: 1500,
    parse_error: e.message
  };
}

// Clean script for TTS (remove stage directions)
const ttsScript = audioScript.podcast_script
  .replace(/\[PAUSE\]/g, '... ')
  .replace(/\[EMPHASIS[^\]]*\]/g, '')
  .replace(/\[.*?\]/g, '')
  .trim();

return [{
  json: {
    ...langData,
    podcast_title: audioScript.podcast_title,
    podcast_script: audioScript.podcast_script,
    tts_script: ttsScript,
    estimated_duration: audioScript.estimated_duration,
    word_count: audioScript.word_count,
    chapters: audioScript.chapters || [],
    show_notes: audioScript.show_notes || '',
    keywords: audioScript.keywords || [],
    affiliate_mentions: audioScript.affiliate_mentions || [],
    voice_provider: voiceConfig.provider,
    voice_id: voiceConfig.voice_id,
    voice_name: voiceConfig.name
  }
}];

const item = $input.first();
const scriptData = $('📝 Parse Audio Script').item.json;
const slug = (scriptData.url || '').split('/').filter(Boolean).pop() || (scriptData.title || 'post').replace(/[^a-z0-9-]/gi, '_').slice(0, 50);
const lang = scriptData.language || 'en';
const ts = Date.now();
const fileName = `${slug}_${lang}_${ts}.mp3`;

let audioFile;
let audioFormat = 'mp3';
if (item.binary && item.binary.data) {
  audioFile = item.binary.data;
} else if (item.json && item.json.audioContent) {
  audioFile = Buffer.from(item.json.audioContent, 'base64');
} else if (item.json && item.json.data) {
  audioFile = item.json.data;
} else {
  audioFile = null;
}

return [{
  json: {
    ...scriptData,
    audio_file_name: fileName,
    audio_format: audioFormat,
    audio_size_kb: audioFile ? Math.round(audioFile.length / 1024) : 0,
    audio_ready: !!audioFile,
    generated_at: new Date().toISOString(),
    voice_provider: scriptData.voice_provider || 'local'
  },
  binary: audioFile ? { data: audioFile, fileName, mimeType: 'audio/mpeg' } : undefined
}];

const config = $('⚙️ Load Config').item.json;
const basePath = (config.AUDIO_OUTPUT_PATH || '/tmp/htg-audio').replace(/\/$/, '');
const item = $input.first();
const j = item.json;
const fileName = j.audio_file_name || `audio_${j.language}_${Date.now()}.mp3`;
const fullPath = basePath + '/' + fileName;
let buf = null;
if (item.binary && item.binary.data) buf = item.binary.data;
if (buf && typeof require !== 'undefined') {
  try { const fs = require('fs'); fs.mkdirSync(basePath, { recursive: true }); fs.writeFileSync(fullPath, buf); } catch (e) { }
}
return [{ json: { ...j, file_path: fullPath, audio_file_name: fileName } }];

const rows = $input.all().map(i => i.json);
const keys = new Set();
const dateKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase() === 'date');
const langKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase() === 'language');
const urlKey = Object.keys(rows[0] || {}).find(k => (k || '').toLowerCase().includes('url') || (k || '').toLowerCase() === 'blog url');
rows.forEach(r => {
  const d = (r[dateKey] || r.Date || '').toString().slice(0, 10);
  const lang = (r[langKey] || r.Language || '').toString();
  const url = (r[urlKey] || r['Blog URL'] || r.url || '').toString();
  const slug = url.split('/').filter(Boolean).pop() || '';
  keys.add((slug || url) + '_' + d + '_' + lang);
});
return [{ json: { existingKeys: Array.from(keys) } }];

const config = $('⚙️ Load Config').item.json;
const tz = config.CONTENT_DAY_TIMEZONE || config.TIMEZONE || 'UTC';
const contentDate = new Date().toLocaleDateString('en-CA', { timeZone: tz });
const j = $input.first().json;
const slug = (j.url || '').split('/').filter(Boolean).pop() || '';
const idempotencyKey = (slug || j.url || '') + '_' + contentDate + '_' + (j.language || '');
return [{ json: { ...j, idempotency_key: idempotencyKey, log_date: contentDate } }];

const items = $input.all();
const out = [];
for (const it of items) {
  const j = it.json;
  const existing = j.existingKeys || [];
  if (!j.idempotency_key || existing.includes(j.idempotency_key)) continue;
  const { existingKeys, ...logRow } = j;
  out.push({ json: logRow });
}
return out;
